local BUI, E, L, V, P, G = unpack((select(2, ...)))
local format = format

local function CallbackFunction(accepted)
	if not accepted then
		return
	end

	BUI:Print(format(BUI.profileStrings[1], L['BigWigs']))
end

function BUI:LoadBigWigsProfile()
	local key = BUI.AddonProfileKey
	local profileName = BigWigsLoader.db:GetCurrentProfile()

	if profileName ~= key then
		local profileString = "BW2:"
		BigWigsAPI.RegisterProfile(BUI.Title, profileString, key, CallbackFunction)
		return
	else
		BUI:Print(format(BUI.profileStrings[2], L['BigWigs']))
	end
end
